def translate_question(source: str, language: str) -> str | None:
    if source in Q:
        return Q[source][language]
    return business_question(source, language)


def main() -> None:
    source_data = json.loads((ROOT / "ru.lproj" / "data.json").read_text(encoding="utf-8"))
    for language in LANGUAGES:
        path = ROOT / f"{language}.lproj" / "data.json"
        data = json.loads(path.read_text(encoding="utf-8"))
        for source_theme, target_theme in zip(source_data, data, strict=True):
            for source_question, target_question in zip(source_theme["questions"], target_theme["questions"], strict=True):
                translated = translate_question(source_question["question"], language)
                if translated:
                    target_question["question"] = translated
        path.write_text(json.dumps(data, ensure_ascii=False, indent=4) + "\n", encoding="utf-8")
        print(f"Updated {path}")


if __name__ == "__main__":
    main()
